"use client";

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Alert, Card, CardContent, Stack, TextField, Typography } from "@mui/material";

import { DataTable } from "@/components/ui/data-table";
import { formatDateTime } from "@/lib/formatters";
import { fetchActivity } from "@/services/activity";
import { ActivityItem } from "@/services/types";

export default function ActivityPage() {
  const [year, setYear] = useState<string>("2026");
  const query = useQuery({
    queryKey: ["activity", year],
    queryFn: () => fetchActivity(Number(year)),
    staleTime: 2 * 60_000,
    placeholderData: (previousData) => previousData
  });

  const items: ActivityItem[] = query.data ?? [];

  return (
    <Stack spacing={2}>
      <Card>
        <CardContent>
          <Typography variant="h4">Activity History</Typography>
          <Typography color="text.secondary" sx={{ mb: 2 }}>
            See who changed what and when.
          </Typography>
          <TextField
            label="Year"
            type="number"
            value={year}
            onChange={(event) => setYear(event.target.value)}
            sx={{ maxWidth: 220 }}
          />
        </CardContent>
      </Card>

      {query.isPending ? <Alert severity="info">Loading activity...</Alert> : null}
      {query.isError ? <Alert severity="error">Unable to load activity history.</Alert> : null}
      {!query.isPending && !query.isError && items.length === 0 ? (
        <Typography color="text.secondary">No activity recorded for this year yet.</Typography>
      ) : null}

      {!query.isPending && !query.isError && items.length > 0 ? (
        <Card>
          <CardContent>
          <DataTable
            rows={items.map((item) => ({ ...item, id: item.id }))}
            columns={[
              { key: "actor", header: "Actor", render: (item) => item.actor.display_name },
              { key: "summary", header: "Action", render: (item) => item.summary },
              { key: "year", header: "Year", render: (item) => item.planning_year },
              {
                key: "date",
                header: "When",
                render: (item) => formatDateTime(item.created_at)
              }
            ]}
          />
          </CardContent>
        </Card>
      ) : null}
    </Stack>
  );
}
